INSERT INTO questions (question_id, stem, options, answer, explanation, question_type, difficulty, knowledge_path, source_type, status, created_at) VALUES ('q_econ_051', '下列弹性的表达中，正确的是', '[{"label": "A", "content": "需求价格弹性是需求量变动对价格变动的敏感程度"}, {"label": "B", "content": "需求价格弹性等于需求的变动量除以价格的变动量"}, {"label": "C", "content": "收入弹性描述的是收入与价格的关系"}, {"label": "D", "content": "收入弹性描述的是收入与需求量的关系"}]', 'ADE', '', 'multi', 'medium', '微观经济学/第一章', 'seed', 'active', '2026-06-27T00:00:00.000Z');
INSERT INTO questions (question_id, stem, options, answer, explanation, question_type, difficulty, knowledge_path, source_type, status, created_at) VALUES ('q_econ_052', '以下关于需求价格弹性大小的论述，正确的是', '[{"label": "A", "content": "如果需求曲线是一条直线，则直线上各点的需求弹性相等"}, {"label": "B", "content": "如果需求曲线是一条直线，则直线上各点的需求弹性不相等"}, {"label": "C", "content": "如果需求曲线是一条直线，则直线上越往左上方的点需求弹性越大"}, {"label": "D", "content": "如果需求曲线是一条曲线，则曲线上各点的需求弹性相等"}]', 'BC', '', 'multi', 'medium', '微观经济学/第一章', 'seed', 'active', '2026-06-27T00:00:00.000Z');
